// tools/depcheck/main.go
// Run this in CI to enforce dependency security policies
package main

import (
	"fmt"
	"os"
	"os/exec"
	"strings"
)

func main() {
	exitCode := 0

	fmt.Println("=== Supply Chain Security Checks ===")
	fmt.Println()

	// 1. Verify go.sum exists and is committed
	fmt.Println("[CHECK 1] Verifying go.sum exists...")
	if _, err := os.Stat("go.sum"); os.IsNotExist(err) {
		fmt.Println("  FAIL: go.sum is missing. All dependency hashes must be tracked.")
		exitCode = 1
	} else {
		fmt.Println("  PASS: go.sum exists")
	}

	// 2. Verify all modules against go.sum checksums
	fmt.Println("[CHECK 2] Verifying module integrity via go.sum...")
	cmd := exec.Command("go", "mod", "verify")
	output, err := cmd.CombinedOutput()
	if err != nil {
		fmt.Printf("  FAIL: Module verification failed:\n%s\n", string(output))
		exitCode = 1
	} else {
		fmt.Printf("  PASS: %s", string(output))
	}

	// 3. Check that go.mod is tidy (no extraneous or missing deps)
	fmt.Println("[CHECK 3] Checking go.mod is tidy...")
	cmd = exec.Command("go", "mod", "tidy", "-diff")
	output, err = cmd.CombinedOutput()
	if err != nil || len(strings.TrimSpace(string(output))) > 0 {
		fmt.Printf("  FAIL: go.mod is not tidy. Run 'go mod tidy' and commit changes.\n%s\n", string(output))
		exitCode = 1
	} else {
		fmt.Println("  PASS: go.mod is tidy")
	}

	// 4. Scan for known vulnerabilities using govulncheck
	fmt.Println("[CHECK 4] Scanning for known vulnerabilities...")
	cmd = exec.Command("govulncheck", "./...")
	output, err = cmd.CombinedOutput()
	outputStr := string(output)
	fmt.Println(outputStr)
	if err != nil {
		fmt.Println("  FAIL: Vulnerabilities detected. Review and update affected pinned versions.")
		exitCode = 1
	} else {
		fmt.Println("  PASS: No known vulnerabilities found")
	}

	// 5. Check for replace directives that could bypass pinning
	fmt.Println("[CHECK 5] Checking for suspicious replace directives...")
	modContent, err := os.ReadFile("go.mod")
	if err != nil {
		fmt.Printf("  FAIL: Cannot read go.mod: %v\n", err)
		exitCode = 1
	} else {
		lines := strings.Split(string(modContent), "\n")
		hasLocalReplace := false
		for _, line := range lines {
			trimmed := strings.TrimSpace(line)
			if strings.HasPrefix(trimmed, "replace") && strings.Contains(trimmed, "=>") {
				// Local filesystem replaces are a red flag in production
				if strings.Contains(trimmed, "../") || strings.Contains(trimmed, "/home/") || strings.Contains(trimmed, "/tmp/") {
					fmt.Printf("  WARN: Suspicious local replace directive: %s\n", trimmed)
					hasLocalReplace = true
				}
			}
		}
		if hasLocalReplace {
			fmt.Println("  FAIL: Local replace directives must not be in production go.mod")
			exitCode = 1
		} else {
			fmt.Println("  PASS: No suspicious replace directives")
		}
	}

	// 6. Verify GONOSUMCHECK and GONOSUMDB are not set (ensures checksum DB is used)
	fmt.Println("[CHECK 6] Verifying checksum database enforcement...")
	gonosumcheck := os.Getenv("GONOSUMCHECK")
	gonosumdb := os.Getenv("GONOSUMDB")
	goflags := os.Getenv("GOFLAGS")

	if gonosumcheck != "" {
		fmt.Printf("  FAIL: GONOSUMCHECK is set to '%s'. This bypasses integrity checks.\n", gonosumcheck)
		exitCode = 1
	} else if gonosumdb != "" && gonosumdb != "github.com/company/*" {
		fmt.Printf("  FAIL: GONOSUMDB has unexpected value '%s'.\n", gonosumdb)
		exitCode = 1
	} else if strings.Contains(goflags, "-insecure") {
		fmt.Println("  FAIL: GOFLAGS contains -insecure")
		exitCode = 1
	} else {
		fmt.Println("  PASS: Checksum database is enforced")
	}

	fmt.Println()
	fmt.Println("=== Summary ===")
	if exitCode == 0 {
		fmt.Println("All supply chain security checks PASSED")
	} else {
		fmt.Println("Some checks FAILED - see above for details")
	}

	os.Exit(exitCode)
}